import time
import threading
import sys
from typing import Any, Optional, Dict, List


class KeyValueStore:
    def __init__(self):
        self._data: Dict[str, Dict[str, dict]] = {'default': {}}
        self._namespace = 'default'
        self._lock = threading.Lock()

    def set_namespace(self, namespace: str) -> None:
        if not isinstance(namespace, str) or not namespace:
            raise ValueError('Namespace must be a non-empty string')
        with self._lock:
            self._namespace = namespace
            if namespace not in self._data:
                self._data[namespace] = {}

    def set(self, key: str, value: Any, ttl_seconds: Optional[float] = None) -> None:
        if not isinstance(key, str):
            raise TypeError('Key must be a string')
        expires_at = time.time() + ttl_seconds if ttl_seconds is not None else None
        with self._lock:
            self._data[self._namespace][key] = {
                'value': value,
                'expires_at': expires_at,
            }

    def get(self, key: str) -> Optional[Any]:
        with self._lock:
            entry = self._data.get(self._namespace, {}).get(key)
            if entry is None:
                return None
            if entry['expires_at'] is not None and time.time() > entry['expires_at']:
                del self._data[self._namespace][key]
                return None
            return entry['value']

    def delete(self, key: str) -> bool:
        with self._lock:
            ns = self._data.get(self._namespace, {})
            if key in ns:
                del ns[key]
                return True
            return False

    def exists(self, key: str) -> bool:
        return self.get(key) is not None

    def batch_set(self, items: dict, ttl_seconds: Optional[float] = None) -> None:
        expires_at = time.time() + ttl_seconds if ttl_seconds is not None else None
        with self._lock:
            ns = self._data.setdefault(self._namespace, {})
            for key, value in items.items():
                if not isinstance(key, str):
                    raise TypeError('All keys must be strings')
                ns[key] = {'value': value, 'expires_at': expires_at}

    def batch_get(self, keys: list) -> dict:
        return {k: self.get(k) for k in keys}

    def keys(self, pattern: Optional[str] = None) -> List[str]:
        now = time.time()
        with self._lock:
            ns = self._data.get(self._namespace, {})
            result = []
            for k, entry in list(ns.items()):
                if entry['expires_at'] is not None and now > entry['expires_at']:
                    del ns[k]
                    continue
                if pattern is None or k.startswith(pattern):
                    result.append(k)
            return result

    def clear(self) -> None:
        with self._lock:
            self._data[self._namespace] = {}

    def stats(self) -> dict:
        with self._lock:
            count = sum(len(ns) for ns in self._data.values())
            return {
                'count': count,
                'namespaces': list(self._data.keys()),
                'memory_estimate_bytes': sys.getsizeof(self._data),
            }
